constraints.constraint:
Add tenant_id column to widget_view projection table.
Migration: ALTER TABLE widget_view ADD COLUMN tenant_id VARCHAR(255) NOT NULL;
Apply RLS policy from Story 4.4: tenant_id = current_setting('app.tenant_id').

interface.pattern:
@CommandHandler
constructor(command: CreateWidgetCommand) {
  val currentTenant = TenantContext().getCurrentTenantId()
  require(command.tenantId == currentTenant) {
    "Access denied: tenant context mismatch" // Generic message (CWE-209)
  }
  apply(WidgetCreatedEvent(...), MetaData.with("tenant_id", command.tenantId))
}

data class WidgetView(
  val id: UUID,
  val name: String,
  val status: WidgetStatus,
  val tenantId: String // New field for multi-tenancy
)

@EventHandler
fun on(event: WidgetCreatedEvent) {
  val tenantId = TenantContext().getCurrentTenantId() // From Story 4.5 interceptor
  widgetViewRepository.save(WidgetView(
    id = event.widgetId,
    name = event.name,
    status = WidgetStatus.DRAFT,
    tenantId = tenantId
  ))
}
